var ctx = drawingContext;
var w = dimensionContext.width;
var h = dimensionContext.height;
var g = ctx.createLinearGradient(0, 0, 0, h);
g.addColorStop(0, '#040714');
g.addColorStop(0.45, '#120a2a');
g.addColorStop(1, '#08131f');
ctx.fillStyle = g;
ctx.fillRect(0, 0, w, h);

function mountain(x1,y1,x2,y2,x3,y3,fill,stroke){
  ctx.beginPath();
  ctx.moveTo(x1,y1);
  ctx.lineTo(x2,y2);
  ctx.lineTo(x3,y3);
  ctx.closePath();
  ctx.fillStyle = fill;
  ctx.fill();
  ctx.strokeStyle = stroke;
  ctx.lineWidth = 2;
  ctx.stroke();
}

var horizon = h * 0.72;
mountain(w*0.02, horizon, w*0.22, h*0.42, w*0.42, horizon, 'rgba(20,40,70,0.9)', 'rgba(60,220,255,0.22)');
mountain(w*0.28, horizon+8, w*0.50, h*0.34, w*0.72, horizon+8, 'rgba(18,34,62,0.92)', 'rgba(230,80,255,0.22)');
mountain(w*0.56, horizon+2, w*0.78, h*0.46, w*0.98, horizon+2, 'rgba(14,28,52,0.95)', 'rgba(50,255,220,0.2)');

ctx.fillStyle = 'rgba(5,18,20,0.94)';
ctx.fillRect(0, horizon, w, h-horizon);

for (var i = 0; i < 40; i++) {
  var tx = (i / 39) * w + ((i % 3) - 1) * 6;
  var th = 18 + (i % 7) * 6;
  var tw = 10 + (i % 4) * 2;
  var ty = horizon + 2 + (i % 5) * 2;
  ctx.beginPath();
  ctx.moveTo(tx, ty - th);
  ctx.lineTo(tx - tw, ty);
  ctx.lineTo(tx + tw, ty);
  ctx.closePath();
  ctx.fillStyle = (i % 2 === 0) ? 'rgba(35,255,220,0.16)' : 'rgba(220,90,255,0.14)';
  ctx.fill();
}

var flakes = state.flakes;
if (!flakes) return;
ctx.save();
ctx.globalCompositeOperation = 'lighter';
for (var j = 0; j < flakes.length; j++) {
  var f = flakes[j];
  var pulse = 0.75 + 0.25 * Math.sin(framesElapsed * 0.04 + f.phase);
  var a = f.alpha * pulse;
  var r = f.size * 4;
  var glow = ctx.createRadialGradient(f.x, f.y, 0, f.x, f.y, r);
  glow.addColorStop(0, 'hsla(' + Math.floor(f.hue) + ',100%,80%,' + (a * 0.95).toFixed(3) + ')');
  glow.addColorStop(0.35, 'hsla(' + Math.floor(f.hue) + ',100%,65%,' + (a * 0.35).toFixed(3) + ')');
  glow.addColorStop(1, 'hsla(' + Math.floor(f.hue) + ',100%,55%,0)');
  ctx.fillStyle = glow;
  ctx.fillRect(f.x - r, f.y - r, r * 2, r * 2);
  ctx.beginPath();
  ctx.arc(f.x, f.y, f.size * 0.7, 0, Math.PI * 2);
  ctx.fillStyle = 'rgba(235,245,255,' + (a * 0.9).toFixed(3) + ')';
  ctx.fill();
}
ctx.restore();
